import functools
import os
import subprocess
from pathlib import Path

from ...runtime.build import compile_module_from_src
from ..compiler import GPUTarget
from ..driver import GPUDriver

dirname = os.path.dirname(os.path.realpath(__file__))


@functools.lru_cache()
def get_rocm_paths():
    """Discover ROCm installation paths dynamically"""
    try:
        rocm_path = subprocess.check_output(["hipconfig", "--rocmpath"], stderr=subprocess.DEVNULL).decode().strip()
        if os.path.exists(rocm_path):
            return rocm_path
    except (subprocess.CalledProcessError, FileNotFoundError):
        pass

    potential_rocm_paths = [
        "/opt/rocm",
    ]

    try:
        for path in os.listdir("/opt"):
            if path.startswith("rocm-"):
                potential_rocm_paths.append(f"/opt/{path}")
    except FileNotFoundError:
        pass

    for path in potential_rocm_paths:
        if os.path.exists(path) and os.path.isdir(f"{path}/bin") and os.path.isdir(f"{path}/include"):
            if os.path.exists(f"{path}/bin/hipcc") or os.path.exists(f"{path}/bin/hipconfig"):
                return path

    return "/opt/rocm"


@functools.lru_cache()
def get_include_dirs():
    """Get HIP include directories"""
    rocm_path = get_rocm_paths()
    include_dirs = [
        os.path.join(dirname, "include"),
        os.path.join(rocm_path, "include"),
        os.path.join(rocm_path, "include", "hip"),
    ]
    return [path for path in include_dirs if os.path.exists(path)]


@functools.lru_cache()
def get_library_dirs():
    """Get HIP library directories"""
    rocm_path = get_rocm_paths()
    common_lib_paths = [
        os.path.join(rocm_path, "lib"),
        os.path.join(rocm_path, "lib64"),
        "/usr/local/lib",
        "/usr/lib/x86_64-linux-gnu",
        "/usr/lib",
    ]

    env_ld_library_path = os.getenv("LD_LIBRARY_PATH")
    if env_ld_library_path:
        common_lib_paths.extend(env_ld_library_path.split(":"))

    valid_dirs = []
    for path in common_lib_paths:
        if os.path.exists(path) and any(
            os.path.exists(os.path.join(path, lib))
            for lib in ["libamdhip64.so", "libamdhip64.so.7", "libamdhip64.so.6"]
        ):
            valid_dirs.append(path)

    return valid_dirs


include_dirs = get_include_dirs()
libdevice_dir = os.path.join(dirname, "lib")
libraries = ["amdhip64", "hsa-runtime64"]


@functools.lru_cache()
def libhip_dirs():
    """Get HIP library directories (deprecated, use get_library_dirs)"""
    return get_library_dirs()


@functools.lru_cache()
def library_dirs():
    """Get all library directories for compilation"""
    return [libdevice_dir, *get_library_dirs()]


class HipUtils(object):
    def __new__(cls):
        if not hasattr(cls, "instance"):
            cls.instance = super(HipUtils, cls).__new__(cls)
        return cls.instance

    def __init__(self):
        mod = compile_module_from_src(
            src=Path(os.path.join(dirname, "driver.c")).read_text(),
            name="hip_utils",
            library_dirs=library_dirs(),
            include_dirs=include_dirs,
            libraries=libraries,
            ccflags=["-D__HIP_PLATFORM_AMD__"],
        )
        self.load_binary = mod.load_binary


LAUNCHER_PROLOGUE = """
#include <hip/hip_runtime.h>
#include <hip/hip_runtime_api.h>
#include <Python.h>
#include <stdbool.h>
#include <string.h>

static inline void gpuAssert(hipError_t code, const char *file, int line)
{
   if (code != hipSuccess)
   {
      const char* prefix = "Substrate Error [HIP]: ";
      const char* str = hipGetErrorString(code);
      char err[1024] = {0,};
      strcat(err, prefix);
      strcat(err, str);
      PyGILState_STATE gil_state;
      gil_state = PyGILState_Ensure();
      PyErr_SetString(PyExc_RuntimeError, err);
      PyGILState_Release(gil_state);
   }
}

#define HIP_CHECK(ans) gpuAssert((ans), __FILE__, __LINE__);

static void ensureHipContext() {
  hipDevice_t device;
  HIP_CHECK(hipGetDevice(&device));
  // HIP context is created automatically when needed
}


typedef struct _DevicePtrInfo {
    hipDeviceptr_t dev_ptr;
    bool valid;
} DevicePtrInfo;

static PyObject* data_ptr_str = NULL;

static inline DevicePtrInfo getPointer(PyObject *obj, int idx) {
  DevicePtrInfo ptr_info;
  ptr_info.dev_ptr = 0;
  ptr_info.valid = true;
  if (PyLong_Check(obj)) {
    ptr_info.dev_ptr = (hipDeviceptr_t)PyLong_AsUnsignedLongLong(obj);
    return ptr_info;
  }
  if (obj == Py_None) {
    // valid nullptr
    return ptr_info;
  }
  PyObject *ret = PyObject_CallMethodNoArgs(obj, data_ptr_str);
  if (!ret) {
    PyErr_SetString(PyExc_TypeError, "Pointer argument must be either uint64 or have data_ptr method");
    ptr_info.valid = false;
    goto cleanup;
  }
  if (!PyLong_Check(ret)) {
    PyErr_SetString(PyExc_TypeError, "data_ptr method of Pointer object must return 64-bit int");
    ptr_info.valid = false;
    goto cleanup;
  }
  ptr_info.dev_ptr = (hipDeviceptr_t)PyLong_AsUnsignedLongLong(ret);
  if(!ptr_info.dev_ptr)
    return ptr_info;

  // In HIP, device pointers can be used directly
  // No need for additional attribute lookup like in CUDA

cleanup:
  Py_XDECREF(ret);
  return ptr_info;
}
"""

LAUNCHER_EPILOGUE = """static PyMethodDef ModuleMethods[] = {
  {"launch", PyLaunch, METH_VARARGS, "Entry point for all kernels with this signature"},
  {NULL, NULL, 0, NULL} // sentinel
};

static struct PyModuleDef ModuleDef = {
  PyModuleDef_HEAD_INIT,
  "__substrate_launcher",
  NULL, //documentation
  -1, //size
  ModuleMethods
};

PyMODINIT_FUNC PyInit___substrate_launcher(void) {
  PyObject *m = PyModule_Create(&ModuleDef);
  if(m == NULL) {
    return NULL;
  }
  data_ptr_str = PyUnicode_InternFromString("data_ptr");
  if(data_ptr_str == NULL) {{
    return NULL;
  }}
  PyModule_AddFunctions(m, ModuleMethods);
  return m;
}
"""


def make_launcher(constants, signature) -> str:
    from substrate.language import i32, i64, f32, f64

    def ty_to_cpp(ty):
        TYPE_MAP = {
            "i32": "int",
            "i64": "long long",
            "fp32": "float",
            "float": "float",
            "double": "double",
            "u32": "unsigned",
            "u64": "unsigned long long",
        }
        if ty[0] == "*":
            return "hipDeviceptr_t"
        elif ty in TYPE_MAP:
            return TYPE_MAP[ty]
        else:
            raise ValueError(f"Unknown type: {ty}")

    # Grid and block dimensions and function
    _BASE_ARGS_FORMAT = "iiiiiiKK"

    def _flatten_signature(sig, output):
        # Flatten tuples
        if isinstance(sig, tuple):
            for x in sig:
                _flatten_signature(x, output)
        else:
            output.append(sig)

    def _extracted_type(ty):
        if isinstance(ty, tuple):
            val = ",".join(map(_extracted_type, ty))
            return f"[{val}]"
        if ty[0] == "*":
            return "PyObject*"
        if ty in "constexpr":
            return "PyObject*"
        return ty_to_cpp(ty)

    def format_of(ty):
        FORMAT_MAP = {
            "int": "i",
            "long long": "L",
            "unsigned": "I",
            "unsigned long long": "K",
            "float": "f",
            "double": "d",
        }
        if ty in "constexpr":
            return "O"
        if ty[0] == "*":
            return "O"
        else:
            return FORMAT_MAP[ty_to_cpp(ty)]

    args_format = "".join([format_of(ty) for ty in signature.values()])
    format = _BASE_ARGS_FORMAT + args_format

    flat_signature = []
    for sig in signature.values():
        _flatten_signature(sig, flat_signature)
    signature = {i: s for i, s in enumerate(flat_signature)}

    args_list = ", " + ", ".join(f"&_arg{i}" for i, _ in signature.items()) if len(signature) > 0 else ""

    arg_decl_list = []
    for i, ty in signature.items():
        if ty == "constexpr":
            continue
        else:
            arg_decl_list.append(f"{ty_to_cpp(ty)} arg{i}")

    internal_args_list = []
    for i, ty in signature.items():
        if ty[0] == "*":
            internal_args_list.append(f"ptr_info{i}.dev_ptr")
        elif ty != "constexpr":
            internal_args_list.append(f"_arg{i}")

    ptr_decls = [
        f"DevicePtrInfo ptr_info{i} = getPointer(_arg{i}, {i}); if (!ptr_info{i}.valid) return NULL;"
        for i, ty in signature.items()
        if ty[0] == "*"
    ]

    # Use struct-based parameter passing like the working HIP test
    struct_members = []
    for i, ty in signature.items():
        if ty != "constexpr":
            struct_members.append(f"        {ty_to_cpp(ty)} arg{i};")

    struct_decl = "\n".join(struct_members)

    struct_assignments = []
    for i, ty in signature.items():
        if ty != "constexpr":
            struct_assignments.append(f"    kernel_params.arg{i} = arg{i};")

    struct_assign = "\n".join(struct_assignments)

    arg_decl = ", ".join(arg_decl_list)

    hip_launch = f"""
static void HipLaunch(int grid_x, int grid_y, int grid_z, int block_x, int block_y, int block_z, hipStream_t stream, hipFunction_t func{", " + arg_decl if arg_decl else ""}) {{
    // Create parameter structure compatible with HIP
    struct {{
{struct_decl}
    }} kernel_params;

    // Fill parameter structure
{struct_assign}

    size_t paramSize = sizeof(kernel_params);
    void *config[] = {{
        HIP_LAUNCH_PARAM_BUFFER_POINTER, &kernel_params,
        HIP_LAUNCH_PARAM_BUFFER_SIZE, &paramSize,
        HIP_LAUNCH_PARAM_END
    }};

    // Use hipModuleLaunchKernel with config
    HIP_CHECK(hipModuleLaunchKernel(func, grid_x, grid_y, grid_z, block_x, block_y, block_z, 0, stream, NULL, config));
}}

static PyObject *PyLaunch(PyObject *self, PyObject *args) {{
    int grid_x, grid_y, grid_z, block_x, block_y, block_z;
    unsigned long long stream;
    hipFunction_t func;
    {"\n".join([f"{_extracted_type(ty)} _arg{i};" for i, ty in signature.items()])}

    ensureHipContext();
    if (!PyArg_ParseTuple(args, "{format}", &grid_x, &grid_y, &grid_z, &block_x, &block_y, &block_z, &stream, &func {args_list})) {{
        return NULL;
    }}
    {"\n".join(ptr_decls)}

    Py_BEGIN_ALLOW_THREADS;
    HipLaunch(grid_x, grid_y, grid_z, block_x, block_y, block_z, (hipStream_t)stream, func{", " + ", ".join(internal_args_list) if internal_args_list else ""});
    Py_END_ALLOW_THREADS;

    if (PyErr_Occurred()) {{
      return NULL;
    }}
    Py_RETURN_NONE;
}}
"""
    # print('DBG', LAUNCHER_PROLOGUE + hip_launch + LAUNCHER_EPILOGUE)
    return LAUNCHER_PROLOGUE + hip_launch + LAUNCHER_EPILOGUE


class HipLauncher:
    def __init__(self, src):
        constants = src.constants if hasattr(src, "constants") else dict()
        arg_idx = lambda x: (src.fn.arg_names.index(x),) if isinstance(x, str) else x
        constants = {arg_idx(idx): value for idx, value in constants.items()}
        signature = {idx: value for idx, value in src.signature.items()}
        src = make_launcher(constants, signature)
        mod = compile_module_from_src(
            src,
            "__substrate_launcher",
            library_dirs=library_dirs(),
            include_dirs=include_dirs,
            libraries=libraries,
            ccflags=["-D__HIP_PLATFORM_AMD__"],
        )
        self.launch = mod.launch

    def __call__(self, gridX, gridY, gridZ, blockX, blockY, blockZ, stream, function, *args):
        return self.launch(gridX, gridY, gridZ, blockX, blockY, blockZ, stream, function, *args)


class AmdgpuDriver(GPUDriver):
    def __init__(self):
        super().__init__()
        self.launcher_cls = HipLauncher
        self.utils = HipUtils()

    @classmethod
    def is_active(cls):
        # Check for AMD GPU availability via HIP
        try:
            # First try to detect ROCm/HIP installation
            subprocess.check_output(["hipcc", "--version"], stderr=subprocess.DEVNULL)
            return True
        except (subprocess.CalledProcessError, FileNotFoundError):
            # Fallback: try torch.cuda with ROCm backend
            try:
                import torch

                if not torch.cuda.is_available():
                    return False
                # For ROCm builds, check if hipcc is available
                subprocess.run(["hipcc", "--version"], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, check=True)
                return True
            except (subprocess.CalledProcessError, FileNotFoundError, ImportError):
                return False

    @classmethod
    def get_current_target(cls):
        if not cls.is_active():
            raise RuntimeError("No HIP device available for AmdgpuDriver.")

        arch = "gfx90a"

        try:
            result = subprocess.check_output(["rocm-smi", "--showproductname"], stderr=subprocess.DEVNULL).decode()
            lowered = result.lower()
            if "gfx906" in lowered:
                arch = "gfx906"
            elif "gfx908" in lowered:
                arch = "gfx908"
            elif "gfx90a" in lowered:
                arch = "gfx90a"
            if "gfx942" in lowered:
                arch = "gfx942"
            elif "gfx1100" in lowered:
                arch = "gfx1100"
        except subprocess.CalledProcessError:
            pass  # Use default arch if detection fails

        return GPUTarget("amdgcn-amd-amdhsa", arch)

from dataclasses import dataclass

from ..compiler import BaseBackend, GPUTarget
from ...compiler.code_generator import compile_to_binary


@dataclass(frozen=True)
class AmdgpuCompilerOptions:
    num_warps: int = -1


class AmdgpuCompiler(BaseBackend):
    @staticmethod
    def supports_target(target: GPUTarget):
        return target.tuple == "amdgcn-amd-amdhsa"

    def parse_options(self, options) -> object:
        if options is None:
            return AmdgpuCompilerOptions()
        if isinstance(options, AmdgpuCompilerOptions):
            return options

        args = {}
        if "num_warps" in options and options["num_warps"] is not None:
            args["num_warps"] = options["num_warps"]
        return AmdgpuCompilerOptions(**args)

    def compile(self, src, target, options=None):
        if options is None:
            options = self.parse_options({})
        elif isinstance(options, dict):
            options = self.parse_options(options)
        return compile_to_binary(src, target, opt_level=2, options=options)

import ast
import json
import types

import _substrate_bindings as _C


class _LocalNameCollector(ast.NodeVisitor):
    def __init__(self) -> None:
        self.names = set()

    def _add_target(self, target):
        if isinstance(target, ast.Name):
            self.names.add(target.id)
            return
        if isinstance(target, (ast.Tuple, ast.List)):
            for elt in target.elts:
                self._add_target(elt)
            return
        if isinstance(target, ast.Starred):
            self._add_target(target.value)

    def visit_FunctionDef(self, node):
        self.names.add(node.name)

    def visit_AsyncFunctionDef(self, node):
        self.names.add(node.name)

    def visit_ClassDef(self, node):
        self.names.add(node.name)

    def visit_Assign(self, node):
        for target in node.targets:
            self._add_target(target)
        self.generic_visit(node.value)

    def visit_AnnAssign(self, node):
        self._add_target(node.target)
        if node.value is not None:
            self.generic_visit(node.value)

    def visit_AugAssign(self, node):
        self._add_target(node.target)
        self.generic_visit(node.value)

    def visit_For(self, node):
        self._add_target(node.target)
        self.generic_visit(node)

    def visit_AsyncFor(self, node):
        self._add_target(node.target)
        self.generic_visit(node)

    def visit_With(self, node):
        for item in node.items:
            if item.optional_vars is not None:
                self._add_target(item.optional_vars)
        self.generic_visit(node)

    def visit_AsyncWith(self, node):
        for item in node.items:
            if item.optional_vars is not None:
                self._add_target(item.optional_vars)
        self.generic_visit(node)

    def visit_ExceptHandler(self, node):
        if node.name:
            self.names.add(node.name)
        self.generic_visit(node)

    def visit_Import(self, node):
        for alias in node.names:
            self.names.add(alias.asname or alias.name.split(".")[0])

    def visit_ImportFrom(self, node):
        for alias in node.names:
            self.names.add(alias.asname or alias.name)

    def visit_NamedExpr(self, node):
        self._add_target(node.target)
        self.generic_visit(node.value)


def _serialize_constexprs(src) -> str:
    constants = getattr(src, "constants", None) or {}
    global_constants = getattr(src, "global_constants", None) or {}
    if not constants and not global_constants:
        return "[]"
    constexprs_list = []
    for k, info in constants.items():
        param_name = src.fn.arg_names[k[0]]
        constexprs_list.append(
            {
                "name": param_name,
                "type": info["type"],
                "value": info["value"],
            }
        )
    for name, info in global_constants.items():
        constexprs_list.append(
            {
                "name": name,
                "type": info["type"],
                "value": info["value"],
            }
        )
    return json.dumps(constexprs_list)


def _serialize_global_constexprs(global_constants) -> str:
    if not global_constants:
        return "[]"
    constexprs_list = []
    for name, info in global_constants.items():
        constexprs_list.append(
            {
                "name": name,
                "type": info["type"],
                "value": info["value"],
            }
        )
    return json.dumps(constexprs_list)


def _get_function_def(py_module: ast.AST) -> ast.FunctionDef:
    for node in getattr(py_module, "body", []):
        if isinstance(node, ast.FunctionDef):
            return node
    raise ValueError("FunctionDef not found in parsed AST")


class DependenciesFinder(ast.NodeVisitor):
    def __init__(self, jit_callable):
        self.jit_callable = jit_callable
        self.capture = jit_callable.get_capture_scope()
        self.dependencies = []
        self._locals_stack = []

    def _record_dependency(self, target):
        from substrate.runtime.jit import JITCallable

        if isinstance(target, JITCallable) and target is not self.jit_callable:
            self.dependencies.append(target)

    def _collect_local_names(self, node):
        names = set()
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.Lambda)):
            args = node.args
            for arg in args.posonlyargs + args.args + args.kwonlyargs:
                names.add(arg.arg)
            if args.vararg is not None:
                names.add(args.vararg.arg)
            if args.kwarg is not None:
                names.add(args.kwarg.arg)

        collector = _LocalNameCollector()
        if isinstance(node, ast.Lambda):
            collector.visit(node.body)
        else:
            for stmt in node.body:
                collector.visit(stmt)
        names.update(collector.names)
        return names

    def _push_local_names(self, node):
        self._locals_stack.append(self._collect_local_names(node))

    def _pop_local_names(self):
        self._locals_stack.pop()

    def _is_local_name(self, name):
        return any(name in scope for scope in self._locals_stack)

    def visit_Call(self, node: ast.Call):
        if isinstance(node.func, ast.Name):
            if self._is_local_name(node.func.id):
                self.generic_visit(node)
                return
            target = self.capture.get(node.func.id)
            if target is not None:
                self._record_dependency(target)
        elif isinstance(node.func, ast.Attribute):
            if isinstance(node.func.value, ast.Name):
                if self._is_local_name(node.func.value.id):
                    self.generic_visit(node)
                    return
                base = self.capture.get(node.func.value.id)
                if base is not None and hasattr(base, node.func.attr):
                    self._record_dependency(getattr(base, node.func.attr))
        self.generic_visit(node)

    def visit_FunctionDef(self, node):
        self._push_local_names(node)
        self.generic_visit(node)
        self._pop_local_names()

    def visit_AsyncFunctionDef(self, node):
        self._push_local_names(node)
        self.generic_visit(node)
        self._pop_local_names()

    def visit_Lambda(self, node):
        self._push_local_names(node)
        self.generic_visit(node)
        self._pop_local_names()


def _collect_jit_dependencies(jit_fn) -> list:
    from substrate.runtime.jit import JITCallable

    seen = set()
    ordered = []

    def visit(current):
        finder = DependenciesFinder(current)
        finder.visit(current.parse())
        for dep in finder.dependencies:
            if dep in seen:
                continue
            seen.add(dep)
            visit(dep)
            ordered.append(dep)

    if not isinstance(jit_fn, JITCallable):
        return []

    visit(jit_fn)
    return ordered


def _build_import_module(jit_fns: list) -> ast.Module:
    import_nodes = []
    seen_imports = set()

    for fn in jit_fns:
        py_module = fn.parse()
        used_names = {node.id for node in ast.walk(py_module) if isinstance(node, ast.Name)}
        capture = fn.get_capture_scope()
        for name in sorted(used_names):
            value = capture.get(name)
            if isinstance(value, types.ModuleType):
                module_name = value.__name__
                key = (module_name, name if name != module_name else None)
                if key in seen_imports:
                    continue
                seen_imports.add(key)
                asname = None if name == module_name else name
                import_nodes.append(
                    ast.Import(names=[ast.alias(name=module_name, asname=asname)])
                )

    module = ast.Module(body=import_nodes, type_ignores=[])
    return ast.fix_missing_locations(module)


def compile_to_binary(src, target, opt_level: int = 2, options=None):
    constexprs_json = _serialize_constexprs(src)

    jit_deps = _collect_jit_dependencies(src.fn)
    import_module = _build_import_module([src.fn, *jit_deps])

    generator = _C.MLIRGenerator()
    generator.generate_from_python_ast(import_module)

    for dep in jit_deps:
        generator.add_jit_dependency(dep.parse())

    for dep in jit_deps:
        dep_func = _get_function_def(dep.parse())
        dep_globals = {}
        collect_globals = getattr(dep, "_collect_global_constexprs", None)
        if callable(collect_globals):
            dep_globals = collect_globals()
        generator.visit_function_def(
            dep_func, _serialize_global_constexprs(dep_globals), "jit"
        )

    kernel_func = _get_function_def(src.fn.parse())
    generator.visit_function_def(kernel_func, constexprs_json, "kernel")

    num_warps = getattr(options, "num_warps", -1)
    return generator.compile_to_binary_bytes(
        target.tuple, target.chip, opt_level, num_warps
    )

